const dict = { hi, en };
const t = (k) => dict[state.lang]?.[k] || hi[k] || k;
const moneyText = (v) => money.format(Number(v) || 0);
const escapeHtml = (v="") => String(v).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;");
const today = () => { const d = new Date(); return new Date(d.getTime() - d.getTimezoneOffset()*60000).toISOString().slice(0,10); };
const asDate = (v) => v?.toDate ? v.toDate() : new Date(v);
const fmtDate = (v) => { const d=asDate(v); return Number.isNaN(d.getTime()) ? "-" : new Intl.DateTimeFormat("en-GB",{day:"2-digit",month:"2-digit",year:"numeric"}).format(d); };
const inputDate = (v) => { const d=asDate(v); if(Number.isNaN(d.getTime())) return today(); return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`; };
const dateMs = (v) => { const d=asDate(v); return Number.isNaN(d.getTime()) ? 0 : d.getTime(); };
const canEdit = () => ["owner","admin"].includes(state.activeMembership?.role);
const isOwner = () => state.activeMembership?.role === "owner";
const roleText = (r="viewer") => t(r) || r;
const paymentText = (v="") => ({Cash:t("cash"),Online:t("online"),Cheque:t("cheque")}[v] || v);
const catText = (v="") => ({Material:t("material"),Labour:t("labour"),Puja:t("puja"),Utilities:t("utilities"),Other:t("other")}[v] || v);
const setText = (s,v) => { const n=$(s); if(n) n.textContent=v; };
const label = (id,v) => setText(`label[for="${id}"]`, v);
const ph = (id,v) => { const n=$(`#${id}`); if(n) n.placeholder=v; };
const setBtn = (button, value) => { if(!button) return; const text=[...button.childNodes].find((n)=>n.nodeType===Node.TEXT_NODE && n.textContent.trim()); if(text) text.textContent = `\n${value}\n`; else button.append(value); };
function toast(msg,type=""){ const n=document.createElement("div"); n.className=`toast ${type}`.trim(); n.textContent=msg; el.toast?.appendChild(n); setTimeout(()=>n.remove(),3500); }
function busy(button,on,text){ if(!button) return; if(on){ button.dataset.label=button.textContent; button.textContent=text; button.disabled=true; } else { button.textContent=button.dataset.label || button.textContent; button.disabled=false; } }
function firebaseConfigured(){ return ["apiKey","authDomain","projectId","appId"].every((k)=>firebaseConfig[k] && !String(firebaseConfig[k]).startsWith("YOUR_")); }
function ts(value){ return state.f.Timestamp.fromDate(new Date(`${value}T12:00:00`)); }
function membershipId(uid, templeId){ return `${uid}_${templeId}`; }

