function setLanguage(lang){ if(!["hi","en"].includes(lang)) return; state.lang=lang; localStorage.setItem("devnidhi-lang",lang); applyLanguage(); renderAll(); }
function showScreen(name){ if(!state.user && name!=="account") name="account"; if(state.user && !state.activeMembership && !["temple","account"].includes(name)) name="temple"; el.screens.forEach((s)=>s.classList.toggle("active",s.id===`${name}-screen`)); el.navButtons.forEach((b)=>b.classList.toggle("active",b.dataset.screen===name)); el.nav?.classList.toggle("hidden",!state.user || name==="account"); window.scrollTo({top:0,behavior:"smooth"}); }

function renderDashboard(){ const donations=state.chanda.reduce((s,x)=>s+Number(x.amount||0),0), expenses=state.kharcha.reduce((s,x)=>s+Number(x.amount||0),0), donors=new Set(state.chanda.map((x)=>String(x.donorName||"").trim().toLowerCase()).filter(Boolean)), balance=donations-expenses; setText("#total-chanda",moneyText(donations)); setText("#total-kharcha",moneyText(expenses)); setText("#net-balance",moneyText(balance)); setText("#total-donors",donors.size); setText("#total-expenses",state.kharcha.length); setText("#report-balance",moneyText(balance)); setText("#report-income",moneyText(donations)); setText("#report-expense",moneyText(expenses)); setText("#report-people-count",String(donors.size+state.members.length)); const recent=[...state.chanda.map((x)=>({type:"income",title:x.donorName||t("member"),meta:`${fmtDate(x.date)} - ${paymentText(x.paymentMode)}`,amount:x.amount,time:dateMs(x.date)})),...state.kharcha.map((x)=>({type:"outgoing",title:x.description||t("kharcha"),meta:`${fmtDate(x.date)} - ${catText(x.category)}`,amount:x.amount,time:dateMs(x.date)}))].sort((a,b)=>b.time-a.time).slice(0,3); if(el.recent) el.recent.innerHTML=recent.length?recent.map((x)=>`<article class="activity-row"><div class="activity-icon ${x.type==="outgoing"?"outgoing":""}" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.6" stroke-linecap="round" stroke-linejoin="round"><path d="M12 ${x.type==="outgoing"?"5v14M5 12l7 7 7-7":"19V5M5 12l7-7 7 7"}"/></svg></div><div class="activity-main"><span class="activity-title">${escapeHtml(x.title)}</span><span class="activity-meta">${x.type==="outgoing"?"Г ВӨвҖ“Г ВӨВ°Г ВҘВҚГ ВӨЕЎ (Г ВӨВөГ ВҘВҚГ ВӨВҜГ ВӨВҜ)":"Г ВӨВҰГ ВӨВҫГ ВӨВЁ (Г ВӨЕЎГ ВӨвҖҡГ ВӨВҰГ ВӨВҫ)"} ГўвӮ¬Вў ${escapeHtml(x.meta.split(" - ").pop()||x.meta)}</span></div><div class="activity-side"><strong class="activity-amount ${x.type}">${moneyText(x.amount)}</strong><span class="activity-time ${x.type==="outgoing"?"outgoing":""}">${escapeHtml(x.meta.split(" - ")[0]||"05 Г ВӨВ®Г ВӨЛҶ")}</span></div><span class="kebab" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></span></article>`).join(""):`<div class="empty-state">${t("noActivity")}</div>`; }
function chandaDateText(v){ const d=asDate(v); return Number.isNaN(d.getTime()) ? "-" : new Intl.DateTimeFormat("en-GB",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit",hour12:true}).format(d).replace(",",""); }
function sameDay(a,b){ return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate(); }
function sameMonth(a,b){ return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth(); }
function donorTone(name=""){ const tones=["green","blue","amber","purple","pink"]; let n=0; for(const ch of String(name)) n+=ch.charCodeAt(0); return tones[n%tones.length]; }
function donorInitial(name=""){ const key=String(name).trim().toLowerCase(); const known={"ramesh sharma":"\u0930\u093e","sita devi":"\u0938\u093f","mohanlal agrawal":"\u092e\u094b","anil verma":"\u0905\u0902","sunita patel":"\u0938\u0941"}; if(known[key]) return known[key]; const clean=String(name).trim().split(/\s+/).filter(Boolean); return (clean[0]?.slice(0,1)||"?") + (clean[1]?.slice(0,1)||""); }
function paymentMeta(mode=""){ const raw=String(mode||"Cash"); if(/cheque/i.test(raw)) return {cls:"pay-cheque",label:"Cheque",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="6" width="18" height="12" rx="2"/><path d="M7 12h6M16 12h2"/></svg>'}; if(/bank/i.test(raw)) return {cls:"pay-online",label:"Online (Net Banking)",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="m3 10 9-6 9 6"/><path d="M5 10v8M9 10v8M15 10v8M19 10v8M3 18h18"/></svg>'}; if(/online|upi/i.test(raw)) return {cls:"pay-online",label:raw==="Online"?"Online (UPI)":escapeHtml(raw),icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="7" y="2" width="10" height="20" rx="2"/><path d="M11 18h2"/></svg>'}; return {cls:"pay-cash",label:"Cash",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="7" width="18" height="12" rx="2"/><path d="M16 12h5M7 12h4"/></svg>'}; }
function renderChanda(){ const term=(el.chandaSearch?.value||"").trim().toLowerCase(); let rows=state.chanda.filter((x)=>state.chandaFilter==="all"||x.paymentMode===state.chandaFilter); if(term) rows=rows.filter((x)=>`${x.donorName||""} ${x.amount||""} ${x.paymentMode||""}`.toLowerCase().includes(term)); const now=new Date(), todayTotal=state.chanda.reduce((s,x)=>{const d=asDate(x.date); return s+(sameDay(d,now)?Number(x.amount||0):0);},0), monthTotal=state.chanda.reduce((s,x)=>{const d=asDate(x.date); return s+(sameMonth(d,now)?Number(x.amount||0):0);},0); setText("#today-chanda",moneyText(todayTotal)); setText("#month-chanda",moneyText(monthTotal)); setText("#chanda-entry-count",`Kul ${rows.length||state.chanda.length} Entries`); if(!el.chandaList) return; el.chandaList.innerHTML=rows.length?rows.map((x)=>{ const pay=paymentMeta(x.paymentMode), tone=donorTone(x.donorName), actions=canEdit()?`<details class="kebab-menu chanda-kebab"><summary class="kebab-trigger" aria-label="Entry actions"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></summary><div class="kebab-panel"><button type="button" class="kebab-item" data-action="edit" data-id="${x.id}">Edit</button><button type="button" class="kebab-item danger" data-action="delete" data-id="${x.id}">Delete</button></div></details>`:`<span class="chanda-kebab" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></span>`; return `<article class="chanda-row"><div class="chanda-avatar tone-${tone}">${escapeHtml(donorInitial(x.donorName))}</div><div class="chanda-row-main"><p class="chanda-row-name">${escapeHtml(x.donorName||t("member"))}</p><div class="chanda-pay ${pay.cls}">${pay.icon}<span>${pay.label}</span></div><div class="chanda-row-date"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/></svg>${escapeHtml(chandaDateText(x.date))}</div></div><strong class="chanda-row-amount">${moneyText(x.amount)}</strong>${actions}</article>`; }).join(""):`<div class="empty-state">${term?t("noMatchingDonor"):t("noChanda")}</div>`; }
function renderKharcha(){ const term=(el.kharchaSearch?.value||"").trim().toLowerCase(); let rows=state.kharcha.filter((x)=>state.kharchaFilter==="all"||x.category===state.kharchaFilter); if(term) rows=rows.filter((x)=>`${x.description||""} ${x.amount||""} ${x.category||""}`.toLowerCase().includes(term)); if(!el.kharchaList) return; el.kharchaList.innerHTML=rows.length?rows.map((x)=>`<article class="entry-card"><div class="entry-avatar outgoing">-</div><div class="entry-main"><p class="entry-title">${escapeHtml(x.description||t("kharcha"))}</p><div class="entry-meta"><span class="meta-chip cat-${escapeHtml(x.category||"")}">${escapeHtml(catText(x.category))}</span><span class="meta-chip">${escapeHtml(fmtDate(x.date))}</span></div>${x.note?`<p class="entry-note">${escapeHtml(x.note)}</p>`:""}</div><div><strong class="entry-amount outgoing">${moneyText(x.amount)}</strong>${canEdit()?`<div class="entry-actions"><button class="icon-button" type="button" data-action="edit" data-id="${x.id}">Edit</button><button class="icon-button delete" type="button" data-action="delete" data-id="${x.id}">Del</button></div>`:""}</div></article>`).join(""):`<div class="empty-state">${term?t("noMatchingExpense"):t("noKharcha")}</div>`; }
function renderWorkspace(){ const active=state.activeMembership; el.workspaceBar.classList.toggle("hidden",!active); el.chandaPanel.classList.toggle("hidden",!canEdit()); el.kharchaPanel.classList.toggle("hidden",!canEdit()); el.myTemplesCard.classList.toggle("hidden",!state.memberships.length); el.activeTempleCard.classList.toggle("hidden",!active); el.membersCard.classList.toggle("hidden",!active); el.renameTempleForm.classList.toggle("hidden",!active||!isOwner()); el.requestsCard.classList.toggle("hidden",!active||!isOwner()); if(active){ el.workspaceName.textContent=active.templeName; el.workspaceRole.textContent=roleText(active.role); el.workspaceRole.dataset.role=active.role; el.workspaceId.textContent=active.templeId; el.renameTempleInput.value=active.templeName; el.workspaceLocation.textContent=active.templeLocation||""; el.workspaceLocation.classList.toggle("hidden",!active.templeLocation); el.renameLocationInput.value=active.templeLocation||""; setText("#workspace-home-location",active.templeLocation||"Workspace dashboard"); setText("#dashboard-temple-subtitle",active.templeLocation||t("workspace")); } el.templeSwitcher.innerHTML=state.memberships.map((m)=>`<button class="temple-choice ${m.templeId===active?.templeId?"active":""}" data-temple-id="${m.templeId}"><div><strong>${escapeHtml(m.templeName)}</strong><span>${escapeHtml(roleText(m.role))}</span></div></button>`).join(""); el.membersList.innerHTML=state.members.length?state.members.map((m)=>{ const owner=m.role==="owner"; const control=isOwner()&&!owner?`<div class="member-controls"><span class="role-badge" data-role="${m.role}">${escapeHtml(roleText(m.role))}</span><details class="kebab-menu"><summary class="kebab-trigger" aria-label="Member actions">ГғВўГўвӮ¬В№ГӮВ®</summary><div class="kebab-panel"><button type="button" class="kebab-item" data-action="set-admin" data-member-id="${m.id}">${t("makeAdmin")}</button><button type="button" class="kebab-item" data-action="set-viewer" data-member-id="${m.id}">${t("makeViewer")}</button><button type="button" class="kebab-item danger" data-action="remove-member" data-member-id="${m.id}">${t("removeMemberAction")}</button></div></details></div>`:`<span class="role-badge" data-role="${m.role}">${escapeHtml(roleText(m.role))}</span>`; return `<article class="member-row"><div><strong>${escapeHtml(m.displayName||m.email||t("member"))}</strong><span>${escapeHtml(m.email||"")}</span></div>${control}</article>`; }).join(""):`<div class="empty-state">${t("noMembers")}</div>`; el.requestsList.innerHTML=state.requests.length?state.requests.map((r)=>`<article class="member-row"><div><strong>${escapeHtml(r.displayName||r.email||"User")}</strong><span>${escapeHtml(r.email||"")}</span></div><div class="approval-actions"><button class="primary-button compact" data-action="approve" data-role="admin" data-uid="${r.uid}">${t("approveAdmin")}</button><button class="secondary-button compact" data-action="approve" data-role="viewer" data-uid="${r.uid}">${t("approveViewer")}</button><button class="icon-button delete" data-action="reject" data-uid="${r.uid}">x</button></div></article>`).join(""):`<div class="empty-state">${t("noRequests")}</div>`;  const pendingCount=isOwner()?state.requests.length:0; const bell=document.getElementById("notif-bell"), badge=document.getElementById("notif-badge"); if(bell&&badge){ bell.classList.toggle("hidden",!active||!isOwner()); badge.textContent=String(pendingCount); badge.classList.toggle("hidden",pendingCount===0); }}
function renderAccount(){ el.account.textContent=state.user?(state.user.displayName||t("account")):t("signIn"); el.logout.classList.toggle("hidden",!state.user); if(!state.user){ el.workspaceBar.classList.add("hidden"); el.nav.classList.add("hidden"); } }
function renderAll(){ renderDashboard(); renderChanda(); renderKharcha(); renderWorkspace(); renderAccount(); }
function clearWorkspace(){ state.unsubs.forEach((u)=>u()); state.unsubs=[]; state.chanda=[]; state.kharcha=[]; state.members=[]; state.requests=[]; }
function firestoreError(error){ console.error(error); el.loading.classList.add("hidden"); toast(error.code==="permission-denied"?t("cloudDenied"):t("cloudLoad"),"error"); }
function activateTemple(membership){ clearWorkspace(); state.activeMembership=membership||null; resetChanda(); resetKharcha(); renderAll(); if(!membership){ showScreen("temple"); el.loading.classList.add("hidden"); return; } const tid=membership.templeId, f=state.f; state.unsubs.push(f.onSnapshot(f.query(f.collection(state.db,"temples",tid,"chanda"),f.orderBy("date","desc")),(snap)=>{state.chanda=snap.docs.map((d)=>({id:d.id,...d.data()}));renderDashboard();renderChanda();},firestoreError)); state.unsubs.push(f.onSnapshot(f.query(f.collection(state.db,"temples",tid,"kharcha"),f.orderBy("date","desc")),(snap)=>{state.kharcha=snap.docs.map((d)=>({id:d.id,...d.data()}));renderDashboard();renderKharcha();},firestoreError)); state.unsubs.push(f.onSnapshot(f.query(f.collection(state.db,"memberships"),f.where("templeId","==",tid)),(snap)=>{state.members=snap.docs.map((d)=>({id:d.id,...d.data()}));renderWorkspace();renderDashboard();},firestoreError)); if(membership.role==="owner") state.unsubs.push(f.onSnapshot(f.collection(state.db,"temples",tid,"joinRequests"),(snap)=>{state.requests=snap.docs.map((d)=>({id:d.id,...d.data()}));renderWorkspace();},firestoreError)); el.loading.classList.add("hidden"); }
function subscribeMemberships(){ if(state.membershipUnsub) state.membershipUnsub(); const f=state.f, q=f.query(f.collection(state.db,"memberships"),f.where("uid","==",state.user.uid)); state.membershipUnsub=f.onSnapshot(q,{includeMetadataChanges:true},(snap)=>{ state.memberships=snap.docs.map((d)=>({id:d.id,...d.data()})).sort((a,b)=>String(a.templeName).localeCompare(String(b.templeName))); const selected=state.memberships.find((m)=>m.templeId===state.activeMembership?.templeId)||state.memberships[0]||null; if(snap.metadata.hasPendingWrites&&!state.activeMembership){renderWorkspace();return;} if(selected?.templeId!==state.activeMembership?.templeId||selected?.role!==state.activeMembership?.role) activateTemple(selected); else renderWorkspace(); if(!selected){el.loading.classList.add("hidden");showScreen("temple");} },firestoreError); }
async function initialize(){ if(!firebaseConfigured()){ el.config.classList.add("show"); el.loading.classList.add("hidden"); return; } try{ const [appModule,fire,auth]=await Promise.all([import(`${FIREBASE_BASE}/firebase-app.js`),import(`${FIREBASE_BASE}/firebase-firestore.js`),import(`${FIREBASE_BASE}/firebase-auth.js`)]); const app=appModule.initializeApp(firebaseConfig); let db; try{db=fire.initializeFirestore(app,{localCache:fire.persistentLocalCache({tabManager:fire.persistentMultipleTabManager()})});}catch{db=fire.getFirestore(app);} state.db=db; state.auth=auth.getAuth(app); state.f={...fire,...auth}; await auth.setPersistence(state.auth,auth.browserLocalPersistence); auth.onAuthStateChanged(state.auth,(user)=>{ state.user=user; renderAccount(); clearWorkspace(); if(state.membershipUnsub){state.membershipUnsub();state.membershipUnsub=null;} if(user){el.loading.classList.remove("hidden"); subscribeMemberships(); if($("#account-screen").classList.contains("active")) showScreen("temple");} else {state.memberships=[]; state.activeMembership=null; renderWorkspace(); el.loading.classList.add("hidden"); showScreen("account");} }); }catch(error){console.error(error); el.loading.classList.add("hidden"); toast(t("firebaseStartError"),"error");} }
async function googleSignIn(){ const b=$("#google-signin-button"); busy(b,true,t("openingGoogle")); try{ const p=new state.f.GoogleAuthProvider(); p.setCustomParameters({prompt:"select_account"}); await state.f.signInWithPopup(state.auth,p); } catch(error){ console.error(error); toast(`Google sign-in failed (${error.code||"unknown error"}).`,"error"); } finally{ busy(b,false); } }
async function createTemple(e){ e.preventDefault(); const b=e.submitter, data=new FormData(e.currentTarget), name=String(data.get("templeName")).trim(), location=String(data.get("templeLocation")||"").trim(); if(!name) return; busy(b,true,t("creating")); try{ const f=state.f, temple=f.doc(f.collection(state.db,"temples")), member=f.doc(state.db,"memberships",membershipId(state.user.uid,temple.id)), batch=f.writeBatch(state.db); batch.set(temple,{name,location,ownerUid:state.user.uid,createdAt:f.serverTimestamp()}); batch.set(member,{uid:state.user.uid,templeId:temple.id,templeName:name,templeLocation:location,displayName:state.user.displayName||"",email:state.user.email||"",role:"owner",createdAt:f.serverTimestamp()}); await batch.commit(); e.currentTarget.reset(); toast(t("created"),"success"); } catch(error){console.error(error);toast(t("createFailed"),"error");} finally{busy(b,false);} }
async function requestAccess(e){ e.preventDefault(); const b=e.submitter, tid=String(new FormData(e.currentTarget).get("templeId")).trim(); busy(b,true,t("sending")); try{ const f=state.f, temple=await f.getDoc(f.doc(state.db,"temples",tid)); if(!temple.exists()) throw new Error("not-found"); if(state.memberships.some((m)=>m.templeId===tid)) throw new Error("already-member"); await f.setDoc(f.doc(state.db,"temples",tid,"joinRequests",state.user.uid),{uid:state.user.uid,displayName:state.user.displayName||"",email:state.user.email||"",requestedAt:f.serverTimestamp()}); e.currentTarget.reset(); toast(t("accessSent"),"success"); } catch(error){toast(error.message==="not-found"?t("notFound"):error.message==="already-member"?t("alreadyMember"):t("requestFailed"),"error");} finally{busy(b,false);} }
async function approveRequest(uid,role){ const req=state.requests.find((x)=>x.uid===uid); if(!req||!isOwner()) return; const f=state.f, tid=state.activeMembership.templeId; try{ const batch=f.writeBatch(state.db); batch.set(f.doc(state.db,"memberships",membershipId(uid,tid)),{uid,templeId:tid,templeName:state.activeMembership.templeName,displayName:req.displayName||"",email:req.email||"",role,createdAt:f.serverTimestamp()}); batch.delete(f.doc(state.db,"temples",tid,"joinRequests",uid)); await batch.commit(); toast(`${t("approved")} ${roleText(role)}.`, "success"); } catch(error){toast(t("approveFailed"),"error");} }
async function renameTemple(e){ e.preventDefault(); if(!isOwner()) return; const b=e.submitter, data=new FormData(e.currentTarget), name=String(data.get("templeName")).trim(), location=String(data.get("templeLocation")||"").trim(), tid=state.activeMembership.templeId; if(!name) return; if(name===state.activeMembership.templeName&&location===(state.activeMembership.templeLocation||"")) return toast(t("sameName")); busy(b,true,t("saving")); try{ const f=state.f, docs=(await f.getDocs(f.query(f.collection(state.db,"memberships"),f.where("templeId","==",tid)))).docs; for(let i=0;i<docs.length;i+=400){ const batch=f.writeBatch(state.db); if(i===0) batch.update(f.doc(state.db,"temples",tid),{name,location}); docs.slice(i,i+400).forEach((d)=>batch.update(d.ref,{templeName:name,templeLocation:location})); await batch.commit(); } state.activeMembership.templeName=name; state.activeMembership.templeLocation=location; state.memberships.forEach((m)=>{if(m.templeId===tid){m.templeName=name;m.templeLocation=location;}}); renderWorkspace(); toast(t("nameUpdated"),"success"); } catch(error){toast(t("nameFailed"),"error");} finally{busy(b,false);} }
async function changeMemberRole(id,role){ if(!isOwner()||!["admin","viewer"].includes(role)) return; try{ await state.f.updateDoc(state.f.doc(state.db,"memberships",id),{role}); toast(t("roleChanged")||"Role updated","success"); } catch{toast(t("roleFailed"),"error"); renderWorkspace();} }
async function removeMember(id){ if(!isOwner()) return; const m=state.members.find((x)=>x.id===id); if(!m||m.role==="owner") return; if(!confirm(`${m.displayName||m.email||t("member")} ${t("removeConfirm")}`)) return; try{ await state.f.deleteDoc(state.f.doc(state.db,"memberships",id)); toast(t("removed"),"success"); } catch{toast(t("removeFailed"),"error");} }
function resetChanda(){ state.editingChandaId=null; el.chandaForm.reset(); $("#chanda-date").value=today(); el.chandaCancel.classList.add("hidden"); applyLanguage(); }
function resetKharcha(){ state.editingKharchaId=null; el.kharchaForm.reset(); $("#kharcha-date").value=today(); el.kharchaCancel.classList.add("hidden"); applyLanguage(); }
async function saveChanda(e){ e.preventDefault(); if(!canEdit()) return; const b=e.submitter, data=new FormData(e.currentTarget), amount=Number(data.get("amount")); if(!(amount>0)) return toast(t("validAmount"),"error"); const rec={donorName:String(data.get("donorName")).trim(),amount,date:ts(data.get("date")),paymentMode:String(data.get("paymentMode")),note:String(data.get("note")).trim()}; busy(b,true,t("saving")); try{ const base=["temples",state.activeMembership.templeId,"chanda"]; if(state.editingChandaId) await state.f.updateDoc(state.f.doc(state.db,...base,state.editingChandaId),rec); else await state.f.addDoc(state.f.collection(state.db,...base),{...rec,createdAt:state.f.serverTimestamp(),createdBy:state.user.uid}); resetChanda(); toast(t("chandaSaved"),"success"); } catch{toast(t("chandaSaveFailed"),"error");} finally{busy(b,false);} }
async function saveKharcha(e){ e.preventDefault(); if(!canEdit()) return; const b=e.submitter, data=new FormData(e.currentTarget), amount=Number(data.get("amount")); if(!(amount>0)) return toast(t("validAmount"),"error"); const rec={description:String(data.get("description")).trim(),amount,date:ts(data.get("date")),category:String(data.get("category")),note:String(data.get("note")).trim()}; busy(b,true,t("saving")); try{ const base=["temples",state.activeMembership.templeId,"kharcha"]; if(state.editingKharchaId) await state.f.updateDoc(state.f.doc(state.db,...base,state.editingKharchaId),rec); else await state.f.addDoc(state.f.collection(state.db,...base),{...rec,createdAt:state.f.serverTimestamp(),createdBy:state.user.uid}); resetKharcha(); toast(t("kharchaSaved"),"success"); } catch{toast(t("kharchaSaveFailed"),"error");} finally{busy(b,false);} }
async function entryAction(e,type){ const b=e.target.closest("button[data-action]"); if(!b||!canEdit()) return; const items=type==="chanda"?state.chanda:state.kharcha, x=items.find((r)=>r.id===b.dataset.id); if(!x) return; if(b.dataset.action.startsWith("edit")){ if(type==="chanda"){ state.editingChandaId=x.id; $("#donor-name").value=x.donorName||""; $("#chanda-amount").value=x.amount||""; $("#chanda-date").value=inputDate(x.date); $("#payment-mode").value=x.paymentMode||"Cash"; $("#chanda-note").value=x.note||""; el.chandaCancel.classList.remove("hidden"); el.chandaPanel.scrollIntoView({behavior:"smooth"}); } else { state.editingKharchaId=x.id; $("#expense-description").value=x.description||""; $("#kharcha-amount").value=x.amount||""; $("#kharcha-date").value=inputDate(x.date); $("#expense-category").value=x.category||"Other"; $("#kharcha-note").value=x.note||""; el.kharchaCancel.classList.remove("hidden"); el.kharchaPanel.scrollIntoView({behavior:"smooth"}); } applyLanguage(); } else if(b.dataset.action.startsWith("delete")&&confirm(t("deleteConfirm"))){ try{ await state.f.deleteDoc(state.f.doc(state.db,"temples",state.activeMembership.templeId,type,x.id)); toast(t("entryDeleted"),"success"); } catch{toast(t("deleteFailed"),"error");} } }

el.langButtons.forEach((b)=>b.addEventListener("click",()=>setLanguage(b.dataset.lang))); el.navButtons.forEach((b)=>b.addEventListener("click",()=>showScreen(b.dataset.screen))); $$('[data-jump]').forEach((b)=>b.addEventListener("click",()=>showScreen(b.dataset.jump))); $$('[data-focus-form]').forEach((b)=>b.addEventListener("click",()=>{ const type=b.dataset.focusForm; showScreen(type); const panel=type==="chanda"?el.chandaPanel:el.kharchaPanel; if(panel?.classList.contains("hidden")) toast(t("adminNeeded")); else panel.scrollIntoView({behavior:"smooth",block:"start"}); }));
el.chandaFilters?.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-payment]"); if(!b) return; state.chandaFilter=b.dataset.payment; renderChanda(); }); el.kharchaFilters?.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-category]"); if(!b) return; state.kharchaFilter=b.dataset.category; renderKharcha(); }); el.account.addEventListener("click",()=>showScreen(state.user?"temple":"account")); $("#google-signin-button").addEventListener("click",googleSignIn); el.logout.addEventListener("click",async()=>{await state.f.signOut(state.auth); toast(t("signedOut"),"success");}); el.createTempleForm.addEventListener("submit",createTemple); el.joinTempleForm.addEventListener("submit",requestAccess); el.renameTempleForm.addEventListener("submit",renameTemple); el.templeSwitcher.addEventListener("click",(e)=>{const b=e.target.closest("button[data-temple-id]"); if(b) activateTemple(state.memberships.find((m)=>m.templeId===b.dataset.templeId));}); $("#copy-workspace-id").addEventListener("click",async()=>{try{await navigator.clipboard.writeText(state.activeMembership.templeId); toast(t("copied"),"success");}catch{toast(`Workspace ID: ${state.activeMembership.templeId}`);}}); el.membersList.addEventListener("click",(e)=>{ const b=e.target.closest("button[data-action]"); if(!b) return; const details=b.closest("details.kebab-menu"); if(details) details.open=false; if(b.dataset.action==="set-admin") changeMemberRole(b.dataset.memberId,"admin"); else if(b.dataset.action==="set-viewer") changeMemberRole(b.dataset.memberId,"viewer"); else if(b.dataset.action==="remove-member") removeMember(b.dataset.memberId); }); document.addEventListener("toggle",(e)=>{ if(e.target&&e.target.matches&&e.target.matches("details.kebab-menu")&&e.target.open){ document.querySelectorAll("details.kebab-menu[open]").forEach((d)=>{ if(d!==e.target) d.open=false; }); } }, true); el.requestsList.addEventListener("click",async(e)=>{const b=e.target.closest("button[data-action]"); if(!b) return; if(b.dataset.action==="approve") await approveRequest(b.dataset.uid,b.dataset.role); if(b.dataset.action==="reject"&&confirm(t("rejectConfirm"))) await state.f.deleteDoc(state.f.doc(state.db,"temples",state.activeMembership.templeId,"joinRequests",b.dataset.uid));}); el.chandaForm.addEventListener("submit",saveChanda); el.kharchaForm.addEventListener("submit",saveKharcha); el.chandaCancel.addEventListener("click",resetChanda); el.kharchaCancel.addEventListener("click",resetKharcha); el.chandaList.addEventListener("click",(e)=>entryAction(e,"chanda")); el.kharchaList.addEventListener("click",(e)=>entryAction(e,"kharcha")); el.chandaSearch.addEventListener("input",renderChanda); el.kharchaSearch.addEventListener("input",renderKharcha);
function onlineStatus(){ el.offline.classList.toggle("show",!navigator.onLine); } window.addEventListener("online",()=>{onlineStatus();toast(t("backOnline"),"success");}); window.addEventListener("offline",onlineStatus); onlineStatus(); if("serviceWorker" in navigator) window.addEventListener("load",()=>navigator.serviceWorker.register("./service-worker.js").catch(console.warn)); resetChanda(); resetKharcha(); applyLanguage();

// --- Safety net: never let the loading screen hang forever (e.g. auth/network callback stalls) ---
const releaseLoading=(msg)=>{ if(el.loading&&!el.loading.classList.contains("hidden")){ el.loading.classList.add("hidden"); showScreen(state.user ? (state.activeMembership ? "dashboard" : "temple") : "account"); if(msg) toast(msg,"error"); } };
const stopLoadingWithMessage=(msg)=>{ if(el.loading&&!el.loading.classList.contains("hidden")){ const txt=document.getElementById("loading-text"), retry=document.getElementById("loading-retry"); if(txt) txt.textContent=msg; if(retry){ retry.classList.remove("hidden"); retry.onclick=()=>location.reload(); } } };
setTimeout(()=>stopLoadingWithMessage("Network slow lag raha hai ya connection weak hai. Wifi/data check karke Retry dabayein."),7000);
setTimeout(()=>releaseLoading("Loading took too long. Please refresh once if records do not appear."),12000);
window.addEventListener("error",(e)=>{ console.error(e.error||e.message); releaseLoading("Kuch galat ho gaya. Please refresh once."); });
window.addEventListener("unhandledrejection",(e)=>{ console.error(e.reason); releaseLoading("Kuch galat ho gaya. Please refresh once."); });

initialize();
